---@region 支付
function LSdkCpBase:DoPayOrderRequest(payData, tgaData)
    if not gLGameLogin:IsRecharge() then
        GF.ShowMessage(ccClientText(11917))
        return
    end

    if not self._isSupportPay then
        if LOG_INFO_ENABLED then
            printInfoN2("sdk", string.format("sdk name=%s not support pay", self._name))
        end
        GF.ShowMessage("not support pay")
        return
    end

    local nowTime = Time.RawUnityEngineTime.realtimeSinceStartup

    local oldId = tonumber(self._reqOrderData.uniqueId) or 0
    if oldId > 0 then
        if gModelPay:IsCreateOrderReqing(tostring(oldId)) then
            local oldTime = self._reqOrderData.time
            if oldTime > nowTime then
                GF.ShowMessage(ccClientText(11935))
                return
            end
        end
    end

    local url, extraData = self:GetOrderParams(payData, tgaData)

    local uniqueId = self._uniqueId + 1
    if uniqueId > 2147483647 then
        uniqueId = 1
    end
    self._uniqueId = uniqueId

    uniqueId = tostring(uniqueId)

    self._reqOrderData.payData = payData
    self._reqOrderData.tgaData = tgaData
    self._reqOrderData.orderData = {}
    self._reqOrderData.uniqueId = uniqueId
    self._reqOrderData.isDeal = false
    self._reqOrderData.url = url
    self._reqOrderData.time = Time.RawUnityEngineTime.realtimeSinceStartup + 10
    self._reqOrderData.extraData = extraData

    if gModelPay then
        gModelPay:CreateOrderReq(url, payData.orderRefId, uniqueId)
    end
end

---@param payPointRef V_WelfareProductPayPointRef
function LSdkCpBase:GetProductParam(payPointRef)
    local produceCp = payPointRef.channel
    local money = payPointRef.rmbPayPoint
    return produceCp, money,"CNY"
end

function LSdkCpBase:GetOrderParams(payData,taData)
    local deviceType = LPlatformUtil.GetDeviceType()
    local networkType = LPlatformUtil.GetNetworkType()

    local goodsId = tostring(payData.goodsId)
    local payPointRef = gModelPay:GetWelfareProductPayPointRef(payData.payPointRefId)
    local produceCp = ""
    local payCurrency = "CNY"
    if payPointRef then
        local money
        produceCp, money, payCurrency = self:GetProductParam(payPointRef)
        local price = tonumber(money) or 0
        payData.money = money
        taData.price = price
    end

    local model = USystemInfo.deviceName or ""
    if string.isempty(model) then
        model = USystemInfo.deviceModel
        if string.isempty(model) then
            model = "unknown"
        end
    end
    local imei = LNativeHelper.GetImei() or ""
    local macAddress = LNativeHelper.GetMacAddress() or ""
    local uuid = LPlayerPrefs.uuidFirstBoot or ""

    local userId = self:GetSdkAccount() or ""
    local guid = self:GetSdkGuid() or ""
    local kkkChannelId = self:GetSdkDeployId() or 0

    local identityId = gLGameLogin:GetLoginIdentityId() or ""
    local exchangeUrl = gLGameLogin:GetExchangeUrl() or ""
    local platformId = gLGameLogin:GetPlatformId() or 0
    local gameServerId = gLGameLogin:GetServerId() or 0
    local gameServerName = gLGameLogin:GetServerName() or ""
    local gameMergeToSvr = gLGameLogin:GetMergeToSvr() or 0

    local fromId = self:GetSdkPackageId() or ""
    local platformChannelId = gLGameLogin:GetChannelId() or "0"

    local playerLv = gModelPlayer:GetPlayerLv() or 0
    local vipLvl = gModelPlayer:GetVipLevel() or 0
    local playerId = gModelPlayer:GetPlayerId() or 0
    local playerName = gModelPlayer:GetPlayerName() or ""

    local callBackInfo = tostring(gameServerId)

    local sourceTokenList = {
        {"channelId=", platformChannelId},
        {"equipment=", deviceType},
        {"exchangeUrl=", exchangeUrl},
        {"fromId=",fromId},
        {"guid=",guid},
        {"identityId=",identityId},
        {"imei=",imei},
        {"kkkChannelId=",kkkChannelId},
        {"lvl=",playerLv},
        {"mac=",macAddress},
        {"model=",model},
        {"money=",payData.money},
        {"networkType=",networkType},
        {"platformId=",platformId},
        {"playerId=",playerId},
        {"playerName=",playerName},
        {"productName=",(payData.productName or "")},
        {"refId=",(payData.orderRefId or "")},
        {"serverId=",gameServerId},
        {"userId=",userId},
        {"vipLvl=",vipLvl},
        {"productIdCp=",produceCp}
    }

    local encodeNameList = {
        ["equipment="] = 1,
        ["exchangeUrl="] = 1,
        ["model="] = 1,
        ["playerName="]=1,
        ["productName="]=1,
        ["refId="]=1,
        ["productIdCp="] = 1,
    }

    local tokenList = {}
    local encodeList = {}
    for k,v in ipairs(sourceTokenList) do
        local tmpK = v[1]
        local tmpV = tostring(v[2])
        table.insert(tokenList,tmpK..tmpV)

        if encodeNameList[tmpK] and not string.isempty(tmpV) then
            table.insert(encodeList, tmpK..string.urlencode(tmpV))
        else
            table.insert(encodeList, tmpK..tmpV)
        end
    end
    local suffix = table.concat(tokenList,"&")
    local gameToken = suffix..LGameLogin.AuthKey
    gameToken = CS.md5FromString(gameToken)
    local suffixUrlencode = table.concat(encodeList,"&")
    local urlSuffix = "?" .. suffixUrlencode.."&gameToken="..gameToken.."&uuid="..uuid.."&mergeToSvr="..gameMergeToSvr.."&callBackInfo="..callBackInfo.."&goodsId="..goodsId
    urlSuffix = LUtil.MakeB64SendData(urlSuffix)
    local url = gLGameLogin:GetCreateOrderUrl() or ""
    local extraData =
    {
        produceCp = produceCp,
        payCurrency = payCurrency,
        callBackInfo = callBackInfo,
    }
    local httpUrl = string.format("%s%s",url,urlSuffix)
    return httpUrl, extraData
end

function LSdkCpBase:CreateOrderOk(orderResult)
    if not self._reqOrderData then return end
    local reqOrderData = self._reqOrderData
    local uniqueId = reqOrderData.uniqueId
    if orderResult.uniqueId ~= uniqueId then return end
    if reqOrderData.isDeal then return end
    reqOrderData.isDeal = true
    reqOrderData.orderId = orderResult.orderId
    if LOG_INFO_ENABLED then
        printInfoN2("sdk","订单创建成功， 开始请求支付")
    end
    self:OnInternalCreateOrderOk(reqOrderData)
end

function LSdkCpBase:OnInternalCreateOrderOk(orderData)
    if LOG_INFO_ENABLED then
        printInfoN2("sdk","订单创建成功， 请实现sdk请求支付")
    end
    GF.ShowMessage("订单创建成功， 请实现sdk请求支付")
end
